create extension if not exists pgcrypto;
create table public.businesses(id uuid primary key default gen_random_uuid(),owner_id uuid not null references auth.users(id) on delete cascade,name text not null,city text not null default 'Abidjan',district text,phone text,description text,created_at timestamptz default now());
create table public.services(id uuid primary key default gen_random_uuid(),business_id uuid not null references public.businesses(id) on delete cascade,name text not null,duration_minutes int not null check(duration_minutes between 5 and 480),price_xof int not null check(price_xof>=0),created_at timestamptz default now());
create table public.bookings(id uuid primary key default gen_random_uuid(),business_id uuid not null references public.businesses(id) on delete cascade,service_id uuid not null references public.services(id),starts_at timestamptz not null,ends_at timestamptz not null,customer_name text not null,customer_phone text not null,status text not null default 'pending' check(status in ('pending','confirmed','cancelled','paid')),payment_status text not null default 'unpaid' check(payment_status in ('unpaid','pending','paid','failed')),created_at timestamptz default now());
create table public.payments(id uuid primary key default gen_random_uuid(),booking_id uuid not null references public.bookings(id) on delete cascade,provider text not null,transaction_id text unique not null,amount_xof int not null,status text not null default 'pending',raw_payload jsonb,created_at timestamptz default now());
alter table public.businesses enable row level security;alter table public.services enable row level security;alter table public.bookings enable row level security;alter table public.payments enable row level security;
create policy "public read businesses" on public.businesses for select using(true);
create policy "owners insert businesses" on public.businesses for insert with check(auth.uid()=owner_id);
create policy "owners update businesses" on public.businesses for update using(auth.uid()=owner_id);
create policy "public read services" on public.services for select using(true);
create policy "owners manage services" on public.services for all using(exists(select 1 from businesses b where b.id=services.business_id and b.owner_id=auth.uid())) with check(exists(select 1 from businesses b where b.id=services.business_id and b.owner_id=auth.uid()));
create policy "owners read bookings" on public.bookings for select using(exists(select 1 from businesses b where b.id=bookings.business_id and b.owner_id=auth.uid()));
